import React, { useState } from 'react';
import { Sparkles, Box, Upload, Download, RefreshCw, AlertCircle, Megaphone, Palette, Type, User, Video, Copy, Camera, Layout, Crop, Lightbulb, MousePointer2, Eye, MoveUpRight, Layers } from 'lucide-react';
