  imageDescription: string
): Promise<string> => {

  const prompt = `
  Hãy đóng vai một chuyên gia sáng tạo nội dung video ngắn (TikTok/Reels/Shorts).
  Nhiệm vụ: Viết một prompt (câu lệnh) chi tiết để tạo video chuyển động từ một bức ảnh tĩnh marketing.

  Thông tin sản phẩm:
  - Tên: ${productName}
  - Điểm nổi bật (USP): ${usp}

  Bối cảnh hình ảnh hiện tại: ${imageDescription}

  Yêu cầu cấu trúc đầu ra (BẮT BUỘC):

  Đoạn 1: Nhân vật & bối cảnh. Mô tả chi tiết ngoại hình nhân vật, trang phục và không gian xung quanh để AI video hiểu rõ style.

  Đoạn 2: Chuyển động. Mô tả chuyển động tự nhiên (ví dụ: tóc bay nhẹ, mắt chớp, tay cầm sản phẩm cử động nhẹ, ánh sáng thay đổi). Chuyển động phải mượt mà, đậm chất điện ảnh (cinematic).

  Đoạn 3: Lời thoại (Voiceover): Viết một đoạn kịch bản ngắn (khoảng 30-40 từ) giới thiệu sản phẩm hấp dẫn, tone giọng hào hứng, thu hút người xem ngay từ giây đầu tiên.

  Đoạn 4: Thông số kỹ thuật. Mood, ánh sáng, "Tỉ lệ 9:16, độ phân giải 4K, chuyển động mượt, photorealistic, high detail."

  Lưu ý: 
  - Toàn bộ nội dung trả về bằng Tiếng Việt.
  - Không thêm các câu dẫn nhập thừa, chỉ trả về nội dung prompt.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash',
    contents: prompt,
  });

  return response.text || "Không thể tạo prompt.";
};

export const generateVirtualTryOn = async (
  modelImg: ImageAsset,
  description: string,
  lighting: string,
  filter: string,
  beautyOptions: string[],
  backdrop: OptionItem,
  productImg: ImageAsset | null,
  aspectRatio: string = "3:4"
): Promise<string> => {

    // Construct Prompt
    let prompt = `ACT AS a professional fashion stylist and digital editor.
    TASK: Virtual Try-On. Change the outfit of the person in the first image.

    TARGET OUTFIT STYLE: ${description}.

    PHOTOGRAPHY SETTINGS:
    - LIGHTING: ${lighting}.
    - FILTER/TONE: ${filter}.
    - BEAUTY ENHANCEMENTS: ${beautyOptions.join(', ')}.

    REQUIREMENTS:
    1. KEEP IDENTITY: The face and identity of the person in Image 1 MUST remain 100% unchanged.
    2. KEEP POSE: The body pose must remain exactly the same.
    3. OUTFIT FIT: The new outfit must drape naturally over the body, respecting gravity and fabric physics.
    4. QUALITY: High realism, 8k resolution, detailed texture.
    `;

    // Backdrop Logic
    if (backdrop && backdrop.id !== 'original_bg') {
       prompt += `\n5. BACKGROUND REPLACEMENT: Replace the original background completely with: "${backdrop.prompt}". Ensure lighting matches this new environment.`;
    } else {
       prompt += `\n5. KEEP BACKGROUND: The background should remain consistent with the original image unless specified otherwise.`;
    }

    const parts: any[] = [{ text: prompt }];

    // Image 1: The Model (User)
    parts.push({
        inlineData: {
            mimeType: modelImg.mimeType,
            data: modelImg.base64.split(',')[1] // remove data url prefix if present, assuming utility returned full url
        }
    });

    // Image 2: The Clothing Product (Optional)
    if (productImg) {
        prompt += `\nREFERENCE IMAGE: Use the clothing item in the second image as the EXACT source for the new outfit. Apply it to the person in the first image.`;
        parts[0].text = prompt; // Update text part

        parts.push({
            inlineData: {
                mimeType: productImg.mimeType,
                data: productImg.base64.split(',')[1]
            }
        });
    }

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: { parts },
            config: {
                responseModalities: ['IMAGE'],
                temperature: 0.4,
                imageConfig: {
                    aspectRatio: aspectRatio
                }
            }
        });

        // Extract image
        const resultParts = response.candidates?.[0]?.content?.parts;
        if (resultParts) {
            for (const part of resultParts) {
                if (part.inlineData && part.inlineData.data) {
                    return `data:image/png;base64,${part.inlineData.data}`;
                }
            }
        }
        throw new Error("Không nhận được hình ảnh từ AI.");
    } catch (error) {
        console.error("Virtual Try-On Error:", error);
        throw error;
    }
};

